export function getWordsByDifficulty(difficulty) {
    switch (difficulty) {
        case 'easy': return [...WORDS_EASY];
        case 'medium': return [...WORDS_MEDIUM];
        case 'hard': return [...WORDS_HARD];
        case 'mixed': return [...WORDS_EASY, ...WORDS_MEDIUM, ...WORDS_HARD];
    }
}
export function getRandomWords(difficulty, count) {
    const words = getWordsByDifficulty(difficulty);
    const selected = [];
    const used = new Set();
    while (selected.length < count && selected.length < words.length) {
        const idx = Math.floor(Math.random() * words.length);
        if (!used.has(idx)) {
            used.add(idx);
            selected.push(words[idx]);
        }
    }
    return selected;
}
